<?php
require_once __DIR__ . '/../includes/functions.php';
require_admin();
if($_SERVER['REQUEST_METHOD']==='POST'){ require_post_csrf(); try{ $action=$_POST['action'] ?? 'create'; if($action==='create') Category::create($_POST['category_name'] ?? ''); elseif($action==='update') Category::update((int)$_POST['id'], $_POST['category_name'] ?? ''); elseif($action==='delete') Category::delete((int)$_POST['id']); set_flash('success','Category action completed.'); }catch(Throwable $e){ set_flash('danger',$e->getMessage()); } redirect('admin/categories.php'); }
$categories=Category::all(); $pageTitle='Categories'; $activePage='categories'; require __DIR__.'/../includes/header.php';
?>
<main class="container-fluid admin-shell"><div class="row g-4"><aside class="col-lg-2"><?php require __DIR__.'/../includes/sidebar.php'; ?></aside><section class="col-lg-10"><h1 class="section-title mb-4">Category Management</h1><div class="row g-4"><div class="col-lg-4"><div class="card form-card"><div class="card-body"><h5>Add Category</h5><form method="post"><?= csrf_input() ?><input type="hidden" name="action" value="create"><input name="category_name" class="form-control mb-3" placeholder="Category name" required><button class="btn btn-primary w-100">Add</button></form></div></div></div><div class="col-lg-8"><div class="card table-card"><div class="table-responsive"><table class="table align-middle mb-0"><thead class="table-light"><tr><th>Name</th><th>Slug</th><th>Products</th><th>Actions</th></tr></thead><tbody><?php foreach($categories as $cat): ?><tr><td colspan="4"><form method="post" class="row g-2 align-items-center no-loader"><?= csrf_input() ?><input type="hidden" name="id" value="<?= (int)$cat['id'] ?>"><input type="hidden" name="action" value="update"><div class="col-md-4"><input name="category_name" class="form-control" value="<?= e($cat['category_name']) ?>"></div><div class="col-md-3 small text-muted"><?= e($cat['category_slug']) ?></div><div class="col-md-2"><span class="badge bg-primary"><?= (int)$cat['product_count'] ?></span></div><div class="col-md-3"><button class="btn btn-sm btn-outline-primary">Update</button></form><form method="post" class="d-inline confirm-form no-loader"><?= csrf_input() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?= (int)$cat['id'] ?>"><button class="btn btn-sm btn-outline-danger">Delete</button></form></div></td></tr><?php endforeach; if(!$categories): ?><tr><td colspan="4" class="text-center text-muted py-4">No categories.</td></tr><?php endif; ?></tbody></table></div></div></div></div></section></div></main>
<?php require __DIR__.'/../includes/footer.php'; ?>
